  s.status === 'validado' &&
  (!s.ficha || typeof s.ficha !== 'object' || Object.keys(s.ficha).length === 0 || JSON.stringify(s.ficha) === '{}')
);

if (pendentes.length === 0) {
  return [{ json: { _vazio: true, motivo: 'nenhum_subtema_pendente' } }];
}

// Indexar catalisadores por ID
const catMap = {};
for (const cat of catalisadores) {
  if (cat.id) catMap[cat.id] = cat;
}

// Salvar no staticData
const staticData = $getWorkflowStaticData('global');
staticData.catMap = catMap;
staticData.nicho = config.nicho || '';
staticData.fio = config.fio_condutor || '';
staticData.categorias = config.categorias_tematicas || [];

// Limitar a 30 por execução
const limite = Math.min(pendentes.length, 30);
const items = pendentes.slice(0, limite).map(s => ({
  json: {
    id: s.id,
    nome: s.nome,
    descricao: s.descricao || '',
    keywords: s.keywords || [],
    angulo_sugerido: s.angulo_sugerido || '',
    semente_id: s.semente_id,
    catalisadores_ids: s.catalisadores_ids || [],
    mercados: s.mercados || [],
    is_intersecao: s.is_intersecao || false,
    intersecao_comunidades: s.intersecao_comunidades || [],
    is_onda_entre_mercados: s.is_onda_entre_mercados || false,
    onda_idioma_origem: s.onda_idioma_origem || '',
    is_demanda_silenciosa: s.is_demanda_silenciosa || false,
    indice_saturacao: s.indice_saturacao,
    indice_oportunidade: s.indice_oportunidade,
    tipo_oportunidade: s.tipo_oportunidade,
    saturacao_videos_recentes: s.saturacao_videos_recentes,
    saturacao_canais_unicos: s.saturacao_canais_unicos,
    views_youtube_top20: s.views_youtube_top20,
    saturacao_idade_media_dias: s.saturacao_idade_media_dias,
    volume_busca_est: s.volume_busca_est,
    pageviews_wikipedia: s.pageviews_wikipedia,
    upvotes_reddit: s.upvotes_reddit
  }
}));

return items;

// === NR 1.2.3 — Montar Prompt ===
const item = $input.first().json;

if (item._vazio) return [{ json: { _vazio: true } }];

const staticData = $getWorkflowStaticData('global');
const catMap = staticData.catMap || {};

// Resolver catalisadores conectados
const cats = [];
let hasFutureCat = false;
for (const catId of (item.catalisadores_ids || [])) {
  const cat = catMap[catId];
  if (cat) {
    cats.push({
      titulo: cat.titulo,
      tipo: cat.tipo,
      data_lancamento: cat.data_lancamento,
      temas_reais: cat.temas_reais || [],
      status: cat.status
    });
    if (cat.status === 'futuro') hasFutureCat = true;
  }
}

// Bloco catalisadores
let blocoCat = 'Nenhum';
if (cats.length > 0) {
  blocoCat = cats.map(c => {
    let line = `- [${c.tipo}] "${c.titulo}" — lançamento: ${c.data_lancamento || 'TBA'} status: ${c.status}`;
    if (c.temas_reais.length > 0) line += `\n  temas: ${c.temas_reais.join(', ')}`;
    return line;
  }).join('\n');
}

// Montar user prompt
const userPrompt = `## Subtema para Avaliação
Nome: ${item.nome}
Descrição: ${item.descricao || 'N/A'}
Keywords: ${(item.keywords || []).join(', ') || 'N/A'}
Ângulo sugerido (NR 1.2.1): ${item.angulo_sugerido || 'nenhum'}
Mercados: ${(item.mercados || []).join(', ') || 'pt-BR'}
Onda entre mercados: ${item.is_onda_entre_mercados ? 'Sim (origem: ' + item.onda_idioma_origem + ')' : 'Não'}
Interseção de comunidades: ${item.is_intersecao ? 'Sim (' + (item.intersecao_comunidades || []).join(', ') + ')' : 'Não'}
Demanda silenciosa: ${item.is_demanda_silenciosa ? 'Sim' : 'Não'}

## Catalisadores Conectados
${blocoCat}

## Métricas de Saturação (NR 1.2.2 — YouTube)
Índice saturação: ${item.indice_saturacao ?? 'N/A'}/10
Índice oportunidade: ${item.indice_oportunidade ?? 'N/A'}/10
Tipo oportunidade: ${item.tipo_oportunidade || 'N/A'}
Vídeos recentes (365d): ${item.saturacao_videos_recentes ?? 'N/A'}
Canais únicos: ${item.saturacao_canais_unicos ?? 'N/A'}
Views top 20: ${item.views_youtube_top20 ?? 'N/A'}
Idade média: ${item.saturacao_idade_media_dias ?? 'N/A'} dias
Volume busca estimado: ${item.volume_busca_est ?? 'N/A'}
Pageviews Wikipedia: ${item.pageviews_wikipedia ?? 'N/A'}
Upvotes Reddit/HN: ${item.upvotes_reddit ?? 'N/A'}

Avalie este subtema e retorne o JSON conforme instruções do system prompt.`;

// System prompt fixo
const nicho = staticData.nicho || 'conteúdo educativo geral';
const fio = staticData.fio || '';
const categorias = staticData.categorias || [];

const fioBloco = fio ? `\nFio condutor: ${fio}` : '';
const catBloco = categorias.length > 0
  ? `\nCategorias temáticas: ${categorias.join(', ')}`
  : '';

const systemPrompt = `Você é um analista de conteúdo especializado em canais dark/faceless para YouTube, YouTube Shorts, Instagram Reels e Instagram Carrossel, focado no nicho: ${nicho}.${fioBloco}${catBloco}

O conteúdo é produzido de forma 100% automatizada:
- Roteiro: gerado por IA (Claude)
- Imagens: geradas por IA (ComfyUI + Stable Diffusion / Flux)
- Narração: TTS (ElevenLabs ou similar)
- Montagem: programática (FFmpeg/Remotion)
- Carrosséis: imagens estáticas geradas + texto sobreposto

Sua tarefa é avaliar subtemas para produção de conteúdo, gerando uma ficha detalhada e scores para 3 formatos independentes.

Responda APENAS com um JSON válido. Sem markdown, sem backticks, sem explicações antes ou depois.

Estrutura do JSON:

{
  "ficha": {
    "descricao_conteudo": "Descrição de 2-3 frases do conteúdo ideal para este subtema",
    "publico_alvo": "Quem consome esse conteúdo (perfil demográfico e psicográfico)",
    "angulos_cobertos": ["Ângulos que a competição já cobre no YouTube"],
    "angulo_recomendado": "O melhor ângulo diferenciado para este subtema",
    "potencial_serie": true,
    "serie_episodios_estimados": 5,
    "keywords_extra": ["3-5 keywords adicionais para SEO"],
    "tags_tematicas": ["2-3 tags temáticas amplas"],
    "formato_ideal": "video ou short ou carrossel",
    "justificativa": "Por que este subtema tem valor e qual a janela de oportunidade"
  },
  "scores": {
    "video": {
      "oportunidade_mercado": 7,
      "profundidade_narrativa": 8,
      "viabilidade_visual_comfyui": 6,
      "potencial_serie": 7
    },
    "short": {
      "forca_hook": 8,
      "clareza_ideia_unica": 7,
      "viabilidade_visual_comfyui": 6,
      "potencial_viral": 5
    },
    "carrossel": {
      "decomponibilidade": 6,
      "densidade_informacional": 7,
      "viabilidade_visual_comfyui": 6,
      "potencial_save_share": 5
    }
  }
}

Critérios de Avaliação por Formato:

YouTube Video (8-15 min):
- oportunidade_mercado: Use o índice de oportunidade fornecido como base. Ajuste: tipo direta=+2, qualidade=+1, ângulo=0. Cap em 10.
- profundidade_narrativa: Sustenta 8-15 min? Tem arco (setup, desenvolvimento, revelação)?
- viabilidade_visual_comfyui: Stable Diffusion/Flux gera imagens ricas e variadas? Cenas históricas, natureza, diagramas = alto. Conceitos abstratos puros = baixo.
- potencial_serie: Episódio único ou desdobra em 5-15 vídeos? Categorias naturais (tipos, épocas, regiões) = alto.

YouTube Shorts / Instagram Reels (até 60s):
- forca_hook: Fato surpreendente em 2 segundos? "Sabia que..." = alto. Explicação lenta = baixo.
- clareza_ideia_unica: Condensável em 60s sem perder valor? Uma revelação, um fato, um contraste.
- viabilidade_visual_comfyui: Imagem central forte em formato vertical? Menos cenas que vídeo longo, mas cada uma mais impactante.
- potencial_viral: Compartilhável? Gera reação? Replay value?

Instagram Carrossel (5-10 slides):
- decomponibilidade: Quebra naturalmente em slides? Listas, etapas, comparações = alto. Narrativa contínua = baixo.
- densidade_informacional: Cada slide tem valor standalone? Aprende algo novo a cada swipe?
- viabilidade_visual_comfyui: ComfyUI gera imagens estáticas atraentes? Estilo funciona em formato quadrado/vertical?
- potencial_save_share: Conteúdo referência que salvam pra ler depois?

Regras:
- Scores são inteiros de 0 a 10
- Seja rigoroso: score 7+ significa genuinamente bom
- A média esperada dos scores deve ficar em torno de 5-6. Reserve 8+ para subtemas excepcionais.
- Se saturado mas tem ângulo diferenciado, reflita nos scores
- Canal dark/faceless: sem rosto, sem personalidade do criador
- TUDO é gerado por IA: temas que dependem de filmagem real = viabilidade 0
- angulos_cobertos deve ser array de strings curtas descrevendo cada ângulo já existente no YouTube`;

// Metadata para o Extrair Ficha
return [{
  json: {
    systemPrompt,
    userPrompt,
    _subtema: {
      id: item.id,
      is_demanda_silenciosa: item.is_demanda_silenciosa || false,
      is_onda_entre_mercados: item.is_onda_entre_mercados || false,
      hasFutureCat,
      indice_oportunidade: item.indice_oportunidade
    }
  }
}];

// === NR 1.2.3 — Extrair Ficha ===
const input = $input.first().json;

// Recuperar metadados do subtema via referência direta (padrão NR 1.2.1)
let meta = {};
try {
  meta = $('Montar Prompt').first().json._subtema || {};
} catch(e) {
  meta = {};
}

if (!meta.id) {
  return [{ json: { _vazio: true, motivo: 'sem_metadata_subtema' } }];
}

if (input._vazio) return [{ json: { _vazio: true } }];

// Ler resposta do Claude (campo varia por versão do n8n)
const textoResposta = (input.text || input.output || input.response || '').trim();

if (!textoResposta) {
  return [{ json: { _vazio: true, motivo: 'resposta_vazia', subId: meta.id } }];
}

// Limpar possíveis backticks/markdown
let limpo = textoResposta.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

// Parse JSON com fallback regex
let parsed;
try {
  parsed = JSON.parse(limpo);
} catch(e) {
  const match = limpo.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch(e2) {
      return [{ json: { _vazio: true, motivo: 'json_invalido', subId: meta.id, resposta: limpo.substring(0, 500) } }];
    }
  } else {
    return [{ json: { _vazio: true, motivo: 'json_nao_encontrado', subId: meta.id, resposta: limpo.substring(0, 500) } }];
  }
}

const ficha = parsed.ficha || {};
const scores = parsed.scores || {};

// === Calcular scores ponderados por formato ===

const calcVideo = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.oportunidade_mercado || 0) * 0.30 +
    (s.profundidade_narrativa || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_serie || 0) * 0.20
  ) * 100) / 100;
};

const calcShort = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.forca_hook || 0) * 0.25 +
    (s.clareza_ideia_unica || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_viral || 0) * 0.25
  ) * 100) / 100;
};

const calcCarrossel = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.decomponibilidade || 0) * 0.30 +
    (s.densidade_informacional || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_save_share || 0) * 0.20
  ) * 100) / 100;
};

let scoreVideo = calcVideo(scores.video);
let scoreShort = calcShort(scores.short);
let scoreCarrossel = calcCarrossel(scores.carrossel);

// === Aplicar boosts ===
let boost = 0;
if (meta.is_demanda_silenciosa) boost += 1.0;
if (meta.hasFutureCat) boost += 0.5;
if (meta.is_onda_entre_mercados) boost += 0.5;

scoreVideo = Math.min(10, Math.round((scoreVideo + boost) * 100) / 100);
scoreShort = Math.min(10, Math.round((scoreShort + boost) * 100) / 100);
scoreCarrossel = Math.min(10, Math.round((scoreCarrossel + boost) * 100) / 100);

// score_final = pico (maior dos 3)
const scoreFinal = Math.max(scoreVideo, scoreShort, scoreCarrossel);

// === Enriquecer ficha com scores detalhados ===
const fichaCompleta = {
  ...ficha,
  scores_detalhados: scores,
  boosts_aplicados: {
    demanda_silenciosa: meta.is_demanda_silenciosa ? 1.0 : 0,
    catalisador_futuro: meta.hasFutureCat ? 0.5 : 0,
    onda_entre_mercados: meta.is_onda_entre_mercados ? 0.5 : 0,
    total: boost
  }
};

// Ângulos cobertos — converter array para string
const angulosCobertos = Array.isArray(ficha.angulos_cobertos)
  ? ficha.angulos_cobertos
  : null;

// Output alinhado com nomes das colunas da tabela (Auto-Map)
return [{
  json: {
    id: meta.id,
    ficha: fichaCompleta,
    score_video: scoreVideo,
    score_short: scoreShort,
    score_carrossel: scoreCarrossel,
    score_final: scoreFinal,
    saturacao_angulos_cobertos: angulosCobertos,
    status: 'scored'
  }
}];

const item = $input.first().json;
if (item._vazio || item._skip || !item.id) {
  return [{ json: { _skip: true } }];
}
return [{ json: item }];

