// Metadata para o Extrair Ficha
return [{
  json: {
    systemPrompt,
    userPrompt,
    _subtema: {
      id: item.id,
      is_demanda_silenciosa: item.is_demanda_silenciosa || false,
      is_onda_entre_mercados: item.is_onda_entre_mercados || false,
      hasFutureCat,
      indice_oportunidade: item.indice_oportunidade
    }
  }
}];

// === NR 1.2.3 — Extrair Ficha ===
const input = $input.first().json;

// Recuperar metadados do subtema via referência direta (padrão NR 1.2.1)
let meta = {};
try {
  meta = $('Montar Prompt').first().json._subtema || {};
} catch(e) {
  meta = {};
}

if (!meta.id) {
  return [{ json: { _vazio: true, motivo: 'sem_metadata_subtema' } }];
}

if (input._vazio) return [{ json: { _vazio: true } }];

// Ler resposta do Claude (campo varia por versão do n8n)
const textoResposta = (input.text || input.output || input.response || '').trim();

if (!textoResposta) {
  return [{ json: { _vazio: true, motivo: 'resposta_vazia', subId: meta.id } }];
}

// Limpar possíveis backticks/markdown
let limpo = textoResposta.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

// Parse JSON com fallback regex
let parsed;
try {
  parsed = JSON.parse(limpo);
} catch(e) {
  const match = limpo.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch(e2) {
      return [{ json: { _vazio: true, motivo: 'json_invalido', subId: meta.id, resposta: limpo.substring(0, 500) } }];
    }
  } else {
    return [{ json: { _vazio: true, motivo: 'json_nao_encontrado', subId: meta.id, resposta: limpo.substring(0, 500) } }];
  }
}

const ficha = parsed.ficha || {};
const scores = parsed.scores || {};

// === Calcular scores ponderados por formato ===

const calcVideo = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.oportunidade_mercado || 0) * 0.30 +
    (s.profundidade_narrativa || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_serie || 0) * 0.20
  ) * 100) / 100;
};

const calcShort = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.forca_hook || 0) * 0.25 +
    (s.clareza_ideia_unica || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_viral || 0) * 0.25
  ) * 100) / 100;
};

const calcCarrossel = (s) => {
  if (!s) return 0;
  return Math.round((
    (s.decomponibilidade || 0) * 0.30 +
    (s.densidade_informacional || 0) * 0.25 +
    (s.viabilidade_visual_comfyui || 0) * 0.25 +
    (s.potencial_save_share || 0) * 0.20
  ) * 100) / 100;
};

let scoreVideo = calcVideo(scores.video);
let scoreShort = calcShort(scores.short);
let scoreCarrossel = calcCarrossel(scores.carrossel);

// === Aplicar boosts ===
let boost = 0;
if (meta.is_demanda_silenciosa) boost += 1.0;
if (meta.hasFutureCat) boost += 0.5;
if (meta.is_onda_entre_mercados) boost += 0.5;

scoreVideo = Math.min(10, Math.round((scoreVideo + boost) * 100) / 100);
scoreShort = Math.min(10, Math.round((scoreShort + boost) * 100) / 100);
scoreCarrossel = Math.min(10, Math.round((scoreCarrossel + boost) * 100) / 100);

// score_final = pico (maior dos 3)
const scoreFinal = Math.max(scoreVideo, scoreShort, scoreCarrossel);

// === Enriquecer ficha com scores detalhados ===
const fichaCompleta = {
  ...ficha,
  scores_detalhados: scores,
  boosts_aplicados: {
    demanda_silenciosa: meta.is_demanda_silenciosa ? 1.0 : 0,
    catalisador_futuro: meta.hasFutureCat ? 0.5 : 0,
    onda_entre_mercados: meta.is_onda_entre_mercados ? 0.5 : 0,
    total: boost
  }
};

// Ângulos cobertos — converter array para string
const angulosCobertos = Array.isArray(ficha.angulos_cobertos)
  ? ficha.angulos_cobertos
  : null;

// Output alinhado com nomes das colunas da tabela (Auto-Map)
return [{
  json: {
    id: meta.id,
    ficha: fichaCompleta,
    score_video: scoreVideo,
    score_short: scoreShort,
    score_carrossel: scoreCarrossel,
    score_final: scoreFinal,
    saturacao_angulos_cobertos: angulosCobertos,
    status: 'scored'
  }
}];

const item = $input.first().json;
if (item._vazio || item._skip || !item.id) {
  return [{ json: { _skip: true } }];
}
return [{ json: item }];
